// WHY runOnceForAllItems + $input.all():
// Gmail Trigger can return items where the email data sits at different levels.
// By inspecting all items and trying multiple access patterns, we handle
// whatever structure the trigger actually produces.
const items = $input.all();
const results = [];

for (const item of items) {
  // Try every known location Gmail Trigger might put the data
  const raw = item.json ?? {};

  const subject = (raw.subject || raw.Subject || raw.headers?.subject || '').toLowerCase();
  const body = (raw.text || raw.textPlain || raw.snippet || raw.body || raw.payload?.body?.data || '').toLowerCase();
  const from = (raw.from || raw.From || raw.headers?.from || '').toLowerCase();

  const rejectionKeywords = [
    'unfortunately', 'not moving forward', 'decided to move',
    'other candidates', 'not a match', 'unsuccessful', 'regret',
    'not selected', 'filled the position', 'will not be proceeding'
  ];
  const interviewKeywords = [
    'interview', 'schedule', 'availability', 'phone screen',
    'next steps', 'speak with you', 'calendar', 'zoom', 'meet'
  ];
  const offerKeywords = [
    'offer', 'congratulations', 'pleased to offer', 'job offer',
    'compensation', 'start date', 'onboarding'
  ];

  let emailType = 'unknown';
  let rejectionStage = 'application';

  if (body.includes('phone') || body.includes('initial')) rejectionStage = 'phone_screen';
  else if (body.includes('technical') || body.includes('coding')) rejectionStage = 'technical';
  else if (body.includes('final') || body.includes('onsite')) rejectionStage = 'final_round';

  if (rejectionKeywords.some(kw => subject.includes(kw) || body.includes(kw))) {
    emailType = 'rejection';
  } else if (offerKeywords.some(kw => subject.includes(kw) || body.includes(kw))) {
    emailType = 'offer';
  } else if (interviewKeywords.some(kw => subject.includes(kw) || body.includes(kw))) {
    emailType = 'interview_invite';
  } else if (subject.includes('application') || subject.includes('received')) {
    emailType = 'acknowledgement';
  }

  const companyFromSubject = subject.replace(/re:|fwd:|fw:|application|position|role|job/gi, '').trim();

  results.push({
    json: {
      subject: raw.subject || raw.Subject || '',
      from: raw.from || raw.From || '',
      body: raw.text || raw.textPlain || raw.snippet || '',
      email_type: emailType,
      rejection_stage: rejectionStage,
      company_hint: companyFromSubject.substring(0, 50),
      classified_at: new Date().toISOString()
    }
  });
}

return results;

const d = $input.first().json;
const stage = d.rejection_stage || 'application';
const company = d.company_hint || 'the company';

let responseTemplate = '';

if (stage === 'phone_screen') {
  responseTemplate = 'Subject: Thank You - ' + company + ' Application

Hi [Recruiter Name],

Thank you for letting me know. I appreciate your time during the phone screen.

I'd be grateful for any feedback on my candidacy.

Best regards,
Odeliya Charitonova';
} else if (stage === 'technical') {
  responseTemplate = 'Subject: Thank You - ' + company + ' Technical Interview

Hi [Interviewer Name],

Thank you for informing me. I enjoyed the technical discussions.

Any feedback on my performance would be greatly appreciated.

Best regards,
Odeliya Charitonova';
} else if (stage === 'final_round') {
  responseTemplate = 'Subject: Thank You - ' + company + ' Interview Process

Hi [Hiring Manager],

Thank you for letting me know after such a thorough process. I'd welcome staying connected.

Best regards,
Odeliya Charitonova';
} else {
  responseTemplate = 'Subject: Thank You - ' + company + ' Application

Hi,

Thank you for letting me know. I appreciate your transparency.

Best regards,
Odeliya Charitonova';
}

return [{
  json: {
    subject: d.subject || '',
    from: d.from || '',
    body: d.body || '',
    email_type: d.email_type || '',
    rejection_stage: stage,
    company_hint: d.company_hint || '',
    classified_at: d.classified_at || '',
    response_template: responseTemplate,
    folder_target: 'Rejected',
    obsidian_status: 'Rejected',
    status_update: 'Rejected - ' + stage,
    update_timestamp: new Date().toISOString()
  }
}];

const d = $input.first().json;
const emailType = d.email_type || 'unknown';
const logDate = new Date().toISOString().substring(0, 10);
const logPath = 'Obsidian_Vault/Email_Log/' + logDate + '-' + emailType + '.md';

const statusContent =
  '# Email Log: ' + (d.subject || 'Unknown Subject') + '\n\n' +
  '- **Date:** ' + logDate + '\n' +
  '- **From:** ' + (d.from || 'Unknown') + '\n' +
  '- **Type:** ' + emailType + '\n' +
  '- **Stage:** ' + (d.rejection_stage || 'N/A') + '\n' +
  '- **New Status:** Rejected\n\n' +
  '## Response Template\n\n' + (d.response_template || 'N/A') + '\n';

const contentBase64 = Buffer.from(statusContent).toString('base64');

return [{
  json: {
    subject: d.subject || '',
    from: d.from || '',
    email_type: emailType,
    rejection_stage: d.rejection_stage || '',
    company_hint: d.company_hint || '',
    response_template: d.response_template || '',
    obsidian_status: 'Rejected',
    log_path: logPath,
    log_content_base64: contentBase64,
    log_commit_message: 'Email log: ' + emailType + ' - ' + (d.subject || '').substring(0, 50)
  }
}];

